<span class="line"><span style="color:#268BD2;">useradd</span><span style="color:#CB4B16;"> -m</span><span style="color:#2AA198;"> 樱花酱</span><span style="color:#586E75;font-style:italic;">  # 创建/home/樱花酱</span></span>
