<span class="line"><span style="color:#268BD2;">journalctl</span><span style="color:#CB4B16;"> -xe</span><span style="color:#859900;"> |</span><span style="color:#268BD2;"> grep</span><span style="color:#2AA198;"> ERROR</span></span>
